import{_ as t,o as d,c as o,ai as i}from"./chunks/framework.C4ntERNc.js";const p=JSON.parse('{"title":"Expressions and Operators","description":"","frontmatter":{"title":"Expressions and Operators","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/formal-reference/expressions-and-operators.md","filePath":"reference-manual/formal-reference/expressions-and-operators.md"}'),r={name:"reference-manual/formal-reference/expressions-and-operators.md"};function a(c,e,s,n,l,h){return d(),o("div",null,[...e[0]||(e[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/formal-reference/expressions-and-operators.md for this page in Markdown format</div><h1 id="expressions-and-operators" tabindex="-1">Expressions and Operators <a class="header-anchor" href="#expressions-and-operators" aria-label="Permalink to “Expressions and Operators”">​</a></h1><h2 id="operator-categories" tabindex="-1">Operator categories <a class="header-anchor" href="#operator-categories" aria-label="Permalink to “Operator categories”">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Operators</th><th>Result width</th></tr></thead><tbody><tr><td>Unary arithmetic</td><td><code>-</code>, <code>+</code></td><td>Input width (must parenthesize)</td></tr><tr><td>Binary arithmetic (add/sub)</td><td><code>+</code>, <code>-</code></td><td>input width</td></tr><tr><td>Binary arithmetic (mul/div/mod)</td><td><code>*</code>, <code>/</code>, <code>%</code></td><td>see definitions</td></tr><tr><td>Bitwise</td><td><code>&amp;</code>, <code>|</code>, <code>^</code>, <code>~</code></td><td>input width</td></tr><tr><td>Logical</td><td><code>&amp;&amp;</code>, <code>||</code>, <code>!</code></td><td>1</td></tr><tr><td>Comparison</td><td><code>==</code>, <code>!=</code>, <code>&lt;</code>, <code>&gt;</code>, <code>&lt;=</code>, <code>&gt;=</code></td><td>1</td></tr><tr><td>Shift</td><td><code>&lt;&lt;</code>, <code>&gt;&gt;</code>, <code>&gt;&gt;&gt;</code></td><td>LHS width</td></tr><tr><td>Ternary</td><td><code>? :</code></td><td>operand width</td></tr><tr><td>Concatenation</td><td><code>{ , }</code></td><td>sum of input widths</td></tr></tbody></table><h2 id="key-operator-rules" tabindex="-1">Key operator rules <a class="header-anchor" href="#key-operator-rules" aria-label="Permalink to “Key operator rules”">​</a></h2><ul><li>Unary <code>-</code> / <code>+</code> must be parenthesized (e.g., <code>(-a)</code>). Result width equals input width.</li><li><code>+</code> / <code>-</code> require equal widths; result width equals operand width. Overflow bits are truncated.</li><li><code>*</code> requires equal widths; result width is <code>2 * N</code> (full product).</li><li><code>/</code> and <code>%</code> require equal widths; result width equals dividend width. Compile-time zero divisor is an error; runtime zero is indeterminate (implementation-defined). See <a href="#division-by-zero">Division by zero</a>.</li><li>Bitwise and comparison operators require equal widths.</li><li>Logical operators (<code>&amp;&amp;</code>, <code>||</code>, <code>!</code>) require width-1 operands.</li><li>Shifts keep LHS width; shift amount can be any width.</li><li><code>&gt;&gt;&gt;</code> is arithmetic right shift (sign-extends from MSB).</li><li>Ternary requires width-1 condition and equal-width branches.</li><li>Concatenation order is MSB-first.</li><li>Any operator producing <code>x</code> bits is subject to the observability rule. Masking is structural, not algebraic. The unused branch of a ternary (<code>? :</code>) is considered structurally masked only if the condition is provably constant at compile time.</li></ul><h2 id="operator-precedence-highest-to-lowest" tabindex="-1">Operator precedence (highest to lowest) <a class="header-anchor" href="#operator-precedence-highest-to-lowest" aria-label="Permalink to “Operator precedence (highest to lowest)”">​</a></h2><ol><li>Parentheses <code>( )</code></li><li>Concatenation <code>{ }</code></li><li>Unary NOT <code>~</code> <code>!</code></li><li>Unary arithmetic <code>-</code> <code>+</code></li><li><code>*</code> <code>/</code> <code>%</code></li><li><code>&lt;&lt;</code> <code>&gt;&gt;</code> <code>&gt;&gt;&gt;</code></li><li>Binary <code>+</code> <code>-</code></li><li>Relational <code>&lt;</code> <code>&gt;</code> <code>&lt;=</code> <code>&gt;=</code></li><li>Equality <code>==</code> <code>!=</code></li><li>Bitwise <code>&amp;</code></li><li>Bitwise <code>^</code></li><li>Bitwise <code>|</code></li><li>Logical <code>&amp;&amp;</code></li><li>Logical <code>||</code></li><li>Ternary <code>? :</code></li></ol><h2 id="assignment-operators" tabindex="-1">Assignment operators <a class="header-anchor" href="#assignment-operators" aria-label="Permalink to “Assignment operators”">​</a></h2><table tabindex="0"><thead><tr><th>Operator</th><th>Meaning</th><th>Aliases?</th><th>Width change allowed?</th></tr></thead><tbody><tr><td><code>=</code></td><td>Alias</td><td>yes</td><td>only with <code>=z</code>/<code>=s</code></td></tr><tr><td><code>=&gt;</code></td><td>Drive</td><td>no</td><td>only with <code>=&gt;z</code>/<code>=&gt;s</code></td></tr><tr><td><code>&lt;=</code></td><td>Receive</td><td>no</td><td>only with <code>&lt;=z</code>/<code>&lt;=s</code></td></tr></tbody></table><ul><li>Suffix <code>z</code> zero-extends the narrower side.</li><li>Suffix <code>s</code> sign-extends the narrower side.</li><li>Truncation is never implicit.</li></ul><h2 id="bit-slicing-and-indexing" tabindex="-1">Bit slicing and indexing <a class="header-anchor" href="#bit-slicing-and-indexing" aria-label="Permalink to “Bit slicing and indexing”">​</a></h2><p><strong>Syntax:</strong> <code>signal[MSB:LSB]</code></p><ul><li>MSB and LSB are nonnegative integers or <code>CONST</code> names.</li><li><code>MSB &gt;= LSB</code> is required.</li><li>Indices are inclusive; width = MSB - LSB + 1.</li><li>Indices must be within declared width.</li></ul><h2 id="concatenation" tabindex="-1">Concatenation <a class="header-anchor" href="#concatenation" aria-label="Permalink to “Concatenation”">​</a></h2><ul><li><code>{a, b, c}</code> produces width = sum(width(a), width(b), width(c)).</li><li>MSB-first ordering: <code>a</code> occupies the most-significant bits.</li><li>Can be used on LHS for decomposition: <code>{hi, lo} = expr;</code></li></ul><h2 id="intrinsic-operators" tabindex="-1">Intrinsic operators <a class="header-anchor" href="#intrinsic-operators" aria-label="Permalink to “Intrinsic operators”">​</a></h2><table tabindex="0"><thead><tr><th>Intrinsic</th><th>Result width</th><th>Description</th></tr></thead><tbody><tr><td><code>uadd(a, b)</code></td><td>max(a, b) + 1</td><td>Unsigned add with carry</td></tr><tr><td><code>sadd(a, b)</code></td><td>max(a, b) + 1</td><td>Signed add with carry (sign-extends)</td></tr><tr><td><code>umul(a, b)</code></td><td>2 * max(a, b)</td><td>Unsigned full product</td></tr><tr><td><code>smul(a, b)</code></td><td>2 * max(a, b)</td><td>Signed full product (sign-extends)</td></tr><tr><td><code>clog2(value)</code></td><td>compile-time int</td><td>Ceiling log2; compile-time contexts only</td></tr><tr><td><code>widthof(signal)</code></td><td>compile-time int</td><td>Declared width of local wire/register</td></tr><tr><td><code>gbit(source, index)</code></td><td>1</td><td>Dynamic single-bit extract</td></tr><tr><td><code>sbit(source, index, set)</code></td><td>width(source)</td><td>Dynamic single-bit set/clear</td></tr><tr><td><code>gslice(source, index, width)</code></td><td>width (constant)</td><td>Dynamic multi-bit extraction</td></tr><tr><td><code>sslice(source, index, width, value)</code></td><td>width(source)</td><td>Dynamic multi-bit overwrite</td></tr><tr><td><code>lit(width, value)</code></td><td>width</td><td>Compile-time integer to sized literal</td></tr><tr><td><code>oh2b(source)</code></td><td>clog2(width(source))</td><td>One-hot to binary encoder</td></tr><tr><td><code>b2oh(index, width)</code></td><td>width (constant)</td><td>Binary to one-hot decoder</td></tr><tr><td><code>prienc(source)</code></td><td>clog2(width(source))</td><td>Priority encoder (MSB-first)</td></tr><tr><td><code>lzc(source)</code></td><td>clog2(width(source)+1)</td><td>Leading zero count</td></tr><tr><td><code>usub(a, b)</code></td><td>max(a, b) + 1</td><td>Unsigned subtract with borrow</td></tr><tr><td><code>ssub(a, b)</code></td><td>max(a, b) + 1</td><td>Signed subtract with overflow</td></tr><tr><td><code>abs(a)</code></td><td>width(a) + 1</td><td>Signed absolute value (MSB=overflow)</td></tr><tr><td><code>umin(a, b)</code></td><td>max(a, b)</td><td>Unsigned minimum</td></tr><tr><td><code>umax(a, b)</code></td><td>max(a, b)</td><td>Unsigned maximum</td></tr><tr><td><code>smin(a, b)</code></td><td>max(a, b)</td><td>Signed minimum</td></tr><tr><td><code>smax(a, b)</code></td><td>max(a, b)</td><td>Signed maximum</td></tr><tr><td><code>popcount(source)</code></td><td>clog2(width(source)+1)</td><td>Population count (number of set bits)</td></tr><tr><td><code>reverse(source)</code></td><td>width(source)</td><td>Bit reversal</td></tr><tr><td><code>bswap(source)</code></td><td>width(source)</td><td>Byte swap (width must be multiple of 8)</td></tr><tr><td><code>reduce_and(source)</code></td><td>1</td><td>AND reduction</td></tr><tr><td><code>reduce_or(source)</code></td><td>1</td><td>OR reduction</td></tr><tr><td><code>reduce_xor(source)</code></td><td>1</td><td>XOR reduction</td></tr></tbody></table><p><strong>Notes:</strong></p><ul><li><code>clog2</code> and <code>widthof</code> are compile-time only. <code>widthof</code> accepts wire, register, or bus identifiers.</li><li><code>lit</code> produces a runtime literal; not valid where a compile-time integer is required.</li><li><code>gbit</code>/<code>gslice</code> out-of-range at runtime returns 0.</li><li><code>sbit</code>/<code>sslice</code> out-of-range at runtime returns source unchanged / ignores out-of-range bits.</li><li><code>oh2b</code> source must be &gt;= 2 bits wide. If no bit is set, result is 0. If multiple bits are set, behavior is hardware-defined.</li><li><code>b2oh</code> width must be a compile-time constant &gt;= 2. Index out of range returns all zeros.</li><li><code>prienc</code> source must be &gt;= 2 bits wide. No bits set returns 0.</li><li><code>lzc</code> all zeros returns width(source).</li><li><code>abs</code> MSB of result is overflow flag (1 only for most-negative input). Lower bits are always the correct magnitude.</li><li><code>bswap</code> source width must be a multiple of 8 (compile-time error otherwise).</li><li><code>reduce_and</code>/<code>reduce_or</code>/<code>reduce_xor</code> map directly to Verilog reduction operators <code>&amp;()</code>, <code>|()</code>, <code>^()</code>.</li></ul><h2 id="division-by-zero" tabindex="-1">Division by zero <a class="header-anchor" href="#division-by-zero" aria-label="Permalink to “Division by zero”">​</a></h2><ul><li>If the divisor is a compile-time constant <code>0</code>, the expression is a compile-time error.</li><li>If the divisor may be <code>0</code> at runtime, the result is indeterminate (implementation-defined): no trap, interrupt, or exception is generated; the hardware divider may produce an arbitrary bit pattern, stall indefinitely, or exhibit undefined timing behavior. Behavior differs between synthesis tools and FPGA vendors.</li><li>Simulation tools must abort on runtime division by zero.</li><li>Division by zero is a design error. The designer is responsible for ensuring the divisor is non-zero via architectural design (guards, masks, or proven invariants). Tools may warn when the divisor is non-constant, but this is advisory only.</li><li><strong>Best practice:</strong> Guard divisions with explicit conditions:</li></ul><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>IF (divisor != 0) {</span></span>
<span class="line"><span>  result = numerator / divisor;</span></span>
<span class="line"><span>} ELSE {</span></span>
<span class="line"><span>  result = safe_fallback;  // Designer-specified behavior</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,23)])])}const m=t(r,[["render",a]]);export{p as __pageData,m as default};
